// Static input
let arr = [2, 6, 10, 55, 32, 45];

// Remove duplicates (optional but safer)
let uniqueArr = [...new Set(arr)];

// Sort the array
uniqueArr.sort((a, b) => a - b);

// Find second smallest and second largest
let secondSmallest = uniqueArr[1];
let secondLargest = uniqueArr[uniqueArr.length - 2];

// Print result
console.log("Second Smallest - " + secondSmallest + ", Second Largest - " + secondLargest);

// Write your solution here
// Static input
let input = "a2b3c4";
let result = "";

// Loop through string
for (let i = 0; i < input.length; i += 2) {
    let char = input[i];        // letter
    let count = parseInt(input[i + 1]); // number

    // Repeat character 'count' times
    result += char.repeat(count);
}

// Print result
console.log(result);
